    from hla.rti1516_2025.enums import ResignAction as ResignAction2025
    from hla.rti1516_2025.exceptions import InvalidMessageRetractionHandle

    server = start_2025_grpc_server()
    owner = None
    subscriber_a = None
    subscriber_b = None
