        assert leader.request(TransportRequest(command="REQUEST_FEDERATION_SAVE", fields=("SAVE-MULTI",))).fields == ()
        assert leader.request(TransportRequest(command="EVOKE")).fields == ("1", "INITIATE_FEDERATE_SAVE", "SAVE-MULTI")
